<?php namespace App\Repositories\Hostel;use App\Repositories\BaseRepository;use App\Models\Hostel\Hostel;use Illuminate\Database\Eloquent\Collection;class HostelRepository extends BaseRepository{    public function __construct(Hostel $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Hostel    {        return $this->query()->where('name', $name)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function getActiveHostels(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function searchHostels(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('address', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByCapacity(int $minCapacity): Collection    {        return $this->query()->where('capacity', '>=', $minCapacity)->get();    }    public function getHostelWithRooms(int $hostelId): ?Hostel    {        return $this->query()->with('rooms')->findOrFail($hostelId);    }    public function getHostelWithAllocations(int $hostelId): ?Hostel    {        return $this->query()->with('allocations')->findOrFail($hostelId);    }    public function countAvailableBeds(int $hostelId): int    {        $hostel = $this->getById($hostelId);        $occupiedBeds = $hostel->allocations()->where('status', 'active')->count();        return $hostel->capacity - $occupiedBeds;    }    public function getByWarden(int $employeeId): ?Hostel    {        return $this->query()->where('warden_id', $employeeId)->first();    }}